    if (expected_size == 0 || expected_size > (SIZE_MAX / 2)) {
        return -1;
    }

    /* Free any previously allocated buffer to avoid leaks, then set to NULL */
    if (ctx->temp_buffer != NULL) {
        free(ctx->temp_buffer);
        ctx->temp_buffer = NULL;
        ctx->buffer_size = 0;
    }

    /* Allocate temporary buffer for decompressed data */
    ctx->temp_buffer = (unsigned char *)malloc(expected_size);
    if (ctx->temp_buffer == NULL) {
        ctx->buffer_size = 0;
        return -1;
    }
    ctx->buffer_size = expected_size;

    /* Calculate payload boundaries */
    size_t payload_offset = HEADER_SIZE;
    size_t payload_size = data_size - HEADER_SIZE - CHECKSUM_SIZE;
    const unsigned char *payload = &compressed_data[payload_offset];
    unsigned char stored_checksum = compressed_data[data_size - 1];

    /* ===== Stage 2: Data Decompression ===== */

    if (ctx->compression_type == 0) {
        /* Type 0: Raw — copy payload directly */
        if (payload_size > ctx->buffer_size) {
            free(ctx->temp_buffer);
            ctx->temp_buffer = NULL;
            ctx->buffer_size = 0;
            return -1;
        }
        memcpy(ctx->temp_buffer, payload, payload_size);
        if (payload_size != expected_size) {
            free(ctx->temp_buffer);
            ctx->temp_buffer = NULL;
            ctx->buffer_size = 0;
            return -1;
        }
    } else if (ctx->compression_type == 1) {
        /* Type 1: RLE — payload is (count, value) pairs */
        if (payload_size % 2 != 0) {
            free(ctx->temp_buffer);
            ctx->temp_buffer = NULL;
            ctx->buffer_size = 0;
            return -1;
        }

        size_t out_pos = 0;
        for (size_t i = 0; i < payload_size; i += 2) {
            unsigned char count = payload[i];
            unsigned char value = payload[i + 1];

            if (count == 0) {
                continue;
            }

            if (out_pos + (size_t)count > ctx->buffer_size) {
                free(ctx->temp_buffer);
                ctx->temp_buffer = NULL;
                ctx->buffer_size = 0;
                return -1;
            }

            memset(&ctx->temp_buffer[out_pos], value, count);
            out_pos += count;
        }

        /* Verify decompressed size matches expected */
        if (out_pos != expected_size) {
            free(ctx->temp_buffer);
            ctx->temp_buffer = NULL;
            ctx->buffer_size = 0;
            return -1;
        }
    } else {
        /* Unsupported compression type */
        free(ctx->temp_buffer);
        ctx->temp_buffer = NULL;
        ctx->buffer_size = 0;
        return -1;
    }

    /* ===== Stage 3: Integrity Verification ===== */

    unsigned char computed_checksum = compute_checksum(ctx->temp_buffer, ctx->buffer_size);
    if (computed_checksum != stored_checksum) {
        /* Checksum mismatch — data corrupted */
        free(ctx->temp_buffer);
        ctx->temp_buffer = NULL;
        ctx->buffer_size = 0;
        return -1;
    }

    /* Success */
    return 0;
}
